mapper.select:
SELECT COUNT(1) FROM series
WHERE slug = #{slug} AND is_delelte = 0 AND deleted_at IS NULL
AND id != #{excludeId}

SELECT s.id, s.title, s.slug, s.description, s.cover_image_url, s.category_id, s.is_completed, s.sort_order, COUNT(sp.post_id) AS post_count FROM series s LEFT JOIN series_posts sp ON s.id = sp.series_id LEFT JOIN posts p ON sp.post_id = p.id AND p.status = 1 AND p.is_delelte = 0 AND p.deleted_at IS NULL WHERE s.is_delelte = 0 AND s.deleted_at IS NULL AND s.created_by = #{createdBy}
AND s.category_id = #{categoryId}
GROUP BY s.id, s.title, s.slug, s.description, s.cover_image_url, s.category_id, s.is_completed, s.sort_order ORDER BY s.sort_order ASC, s.id ASC
